1	/**
2	 * Service-to-service JWT utilities using HS256 (HMAC-SHA256).
3	 * Used by app/platform to authenticate calls to platform service.
4	 *
5	 * Short-lived (60s) tokens with explicit audience and issuer claims.
6	 * Edge-compatible via jose (no Node.js crypto dependency).
7	 */
8	import { jwtVerify, SignJWT } from "jose";
9	
10	import { env } from "../env";
11	
12	/** Verified JWT result returned to callers */
13	export interface VerifiedServiceJWT {
14	  caller: string; // From `iss` claim
15	}
16	
17	/**
18	 * Encode the shared secret as a CryptoKey for HS256.
19	 * Cached at module level -- jose requires Uint8Array or CryptoKey.
20	 */
21	function getSecretKey(): Uint8Array {
22	  return new TextEncoder().encode(env.SERVICE_JWT_SECRET);
23	}
24	
25	/**
26	 * Sign a short-lived service JWT.
27	 *
28	 * @param caller - Identity of the calling service (e.g., "app", "platform")
29	 * @returns Signed JWT string (valid for 60 seconds)
30	 */
31	export async function signServiceJWT(caller: string): Promise<string> {
32	  const now = Math.floor(Date.now() / 1000);
33	
34	  return new SignJWT({} as Record<string, unknown>)
35	    .setProtectedHeader({ alg: "HS256", typ: "JWT" })
36	    .setIssuer(caller)
37	    .setAudience("lightfast-memory")
38	    .setIssuedAt(now)
39	    .setExpirationTime(now + 60)
40	    .sign(getSecretKey());
41	}
42	
43	/**
44	 * Verify an incoming service JWT.
45	 *
46	 * @param token - JWT string from Authorization header
47	 * @returns Verified payload with caller identity
48	 * @throws {Error} If token is invalid, expired, or audience mismatch
49	 */
50	export async function verifyServiceJWT(
51	  token: string
52	): Promise<VerifiedServiceJWT> {
