/**
 * Memory backfill orchestrator
 *
 * Ported from apps/backfill/src/workflows/backfill-orchestrator.ts
 *
 * KEY CHANGES vs backfill service:
 * - Function ID: memory/backfill.orchestrator (was backfill/run.orchestrator)
 * - Trigger: memory/backfill.run.requested (was backfill/run.requested)
 * - cancelOn: memory/backfill.run.cancelled (was backfill/run.cancelled)
 * - Replace createGatewayClient() HTTP calls with direct DB queries
 * - Replace relay.replayCatchup() with direct DB query + inngest.send("memory/webhook.received")
 * - step.invoke() references memoryEntityWorker
 */

import { db } from "@db/app/client";
import {
  gatewayBackfillRuns,
  gatewayInstallations,
  gatewayWebhookDeliveries,
  orgIntegrations,
} from "@db/app/schema";
import { getProvider, type ProviderDefinition } from "@repo/app-providers";
import { and, eq, inArray, notInArray } from "@vendor/db";
import { NonRetriableError } from "@vendor/inngest";
import { log } from "@vendor/observability/log/next";
import { providerConfigs } from "../../lib/provider-configs";
import { getActiveTokenForInstallation } from "../../lib/token-helpers";
import { inngest } from "../client";
import { memoryEntityWorker } from "./memory-entity-worker";

export const memoryBackfillOrchestrator = inngest.createFunction(
  {
    id: "memory/backfill.orchestrator",
    name: "Memory Backfill Orchestrator",
    retries: 3,
    concurrency: [
      // 1 backfill per connection — prevents duplicate backfills
      { limit: 1, key: "event.data.installationId" },
      // 10 total concurrent orchestrators (each lightweight — just fan-out + wait)
      { limit: 10 },
    ],
    cancelOn: [
      {
        event: "memory/backfill.run.cancelled",
        match: "data.installationId",
      },
    ],
    // Orchestrator waits for all entity workers — must accommodate the longest
    // Worst case: 15 work units (5 repos x 3 entities), 5 concurrent, each 2hr
    // = 15/5 * 2hr = 6hr total. Set to 8hr for safety.
    timeouts: { start: "2m", finish: "8h" },
  },
  { event: "memory/backfill.run.requested" },
  async ({ event, step }) => {
    const {
      installationId,
      provider,
      orgId,
      depth,
      entityTypes,
      holdForReplay,
      correlationId,
    } = event.data;

    log.info("[backfill-orchestrator] starting", {
      installationId,
      provider,
      depth,
      entityTypes,
      correlationId,
    });

    if (depth <= 0) {
      throw new NonRetriableError(
        `Invalid depth: ${depth} — must be a positive number of days`
      );
    }

    // ── Step 1: Fetch connection details from DB (replaces gateway HTTP call) ──
    const connection = await step.run("get-connection", async () => {
      const installationRows = await db
        .select()
        .from(gatewayInstallations)
        .where(eq(gatewayInstallations.id, installationId))
        .limit(1);

      const conn = installationRows[0];
      if (!conn) {
        throw new NonRetriableError(`Connection not found: ${installationId}`);
      }
      if (conn.status !== "active") {
        throw new NonRetriableError(
          `Connection is not active: ${installationId} (status: ${conn.status})`
        );
      }
      // Tenant isolation: verify caller-supplied orgId matches the DB-canonical value
      if (conn.orgId !== orgId) {
        throw new NonRetriableError(
          `orgId mismatch: event has "${orgId}" but connection belongs to "${conn.orgId}"`
        );
      }

      // Fetch linked resources from orgIntegrations
      const resources = await db
        .select({
          providerResourceId: orgIntegrations.providerResourceId,
        })
        .from(orgIntegrations)
        .where(
          and(
            eq(orgIntegrations.installationId, installationId),
            eq(orgIntegrations.status, "active")
          )
        );

      return {
        id: conn.id,
        externalId: conn.externalId,
        provider: conn.provider,
        orgId: conn.orgId,
        status: conn.status,
        resources,
      };
    });

    log.info("[backfill-orchestrator] connection fetched", {
      installationId,
      provider,
      resourceCount: connection.resources.length,
      correlationId,
    });

    // ── Step 1b: Fetch backfill history from DB (replaces gateway HTTP call) ──
    const backfillHistory = await step.run("get-backfill-history", async () => {
      return db
        .select({
          entityType: gatewayBackfillRuns.entityType,
          providerResourceId: gatewayBackfillRuns.providerResourceId,
          since: gatewayBackfillRuns.since,
        })
        .from(gatewayBackfillRuns)
        .where(
          and(
            eq(gatewayBackfillRuns.installationId, installationId),
            eq(gatewayBackfillRuns.status, "completed")
          )
        );
    });

    // ── Step 2: Resolve entity types and validate provider ──
    const providerDef = getProvider(provider);
    if (!providerDef) {
      throw new NonRetriableError(
        `No backfill provider for provider: ${provider}`
      );
    }
    if (!providerDef.backfill) {
      throw new NonRetriableError(
        `Provider "${provider}" does not support backfill`
      );
    }

    const resolvedEntityTypes =
      entityTypes && entityTypes.length > 0
        ? entityTypes
        : [...providerDef.backfill.defaultEntityTypes];

    // Compute `since` inside a step so it's deterministic across retries/replays
    const since = await step.run("compute-since", () =>
      new Date(Date.now() - depth * 24 * 60 * 60 * 1000).toISOString()
    );

    // ── Step 2b: Resolve resource names live from provider API ──
    const resolvedResources = await step.run(
      "resolve-resource-meta",
      async () => {
        const config = providerConfigs[provider];
        const { token } = await getActiveTokenForInstallation(
          {
            id: connection.id,
            externalId: connection.externalId,
            provider: connection.provider,
          },
          config,
          providerDef as ProviderDefinition
        );

        // Providers where resourceName is NOT needed for API routing can fall back
        const resourceNameRequiredForRouting = ["github", "sentry"].includes(
          provider
        );

        return Promise.all(
          connection.resources.map(async (r) => {
            try {
              const resourceName =
                await providerDef.backfill!.resolveResourceMeta({
                  providerResourceId: r.providerResourceId,
                  token,
                });
              return { providerResourceId: r.providerResourceId, resourceName };
            } catch (err) {
              log.warn("[backfill] failed to resolve resource meta", {
                providerResourceId: r.providerResourceId,
                error: err instanceof Error ? err.message : String(err),
              });
              if (resourceNameRequiredForRouting) {
                // GitHub/Sentry: resourceName is used in buildRequest pathParams — must skip
                return null;
              }
              // Linear/Vercel: resourceName is only used in adapter output — fallback is safe
              return {
                providerResourceId: r.providerResourceId,
                resourceName: r.providerResourceId,
              };
            }
          })
        ).then((results) =>
          results.filter((r): r is NonNullable<typeof r> => r !== null)
        );
      }
    );

    // ── Step 3: Enumerate work units (resource x entityType) ──
    const workUnits = resolvedResources.flatMap((resource) => {
      return resolvedEntityTypes.map((entityType: string) => ({
        entityType,
        resource: {
          providerResourceId: resource.providerResourceId,
          resourceName: resource.resourceName,
        },
        workUnitId: `${resource.providerResourceId}-${entityType}`,
      }));
    });

    // ── Gap-aware filtering: skip (resource, entityType) pairs covered by prior runs ──
    const filteredWorkUnits = workUnits.filter((wu) => {
      const priorRun = backfillHistory.find(
        (h) =>
          h.entityType === wu.entityType &&
          h.providerResourceId === wu.resource.providerResourceId
      );
      if (!priorRun) {
        return true; // No prior run — must fetch
      }
      // Prior run's since ≤ requested since → already covered
      return new Date(priorRun.since) > new Date(since);
    });

    log.info("[backfill-orchestrator] work units planned", {
      installationId,
      provider,
      total: workUnits.length,
      afterFilter: filteredWorkUnits.length,
      skippedByGapFilter: workUnits.length - filteredWorkUnits.length,
      since,
      correlationId,
    });

    if (filteredWorkUnits.length === 0) {
      return {
        success: true,
        installationId,
        provider,
        workUnits: workUnits.length,
        skipped: workUnits.length,
        dispatched: 0,
        eventsProduced: 0,
        eventsDispatched: 0,
      };
    }

    log.info("[backfill-orchestrator] dispatching entity workers", {
      installationId,
      provider,
      count: filteredWorkUnits.length,
      workUnitIds: filteredWorkUnits.map((wu) => wu.workUnitId),
      correlationId,
    });

    // ── Step 4: Invoke entity workers directly ──
    const completionResults = await Promise.all(
      filteredWorkUnits.map(async (wu) => {
        try {
          const result = await step.invoke(`invoke-${wu.workUnitId}`, {
            function: memoryEntityWorker,
            data: {
              installationId,
              provider,
              orgId,
              entityType: wu.entityType,
              resource: wu.resource,
              since,
              depth,
              holdForReplay,
              correlationId,
            },
            timeout: "4h",
          });
          return {
            entityType: wu.entityType,
            resourceId: wu.resource.providerResourceId,
            success: true,
            eventsProduced: result.eventsProduced,
            eventsDispatched: result.eventsDispatched,
            pagesProcessed: result.pagesProcessed,
          };
        } catch (err) {
          return {
            entityType: wu.entityType,
            resourceId: wu.resource.providerResourceId,
            success: false,
            eventsProduced: 0,
            eventsDispatched: 0,
            pagesProcessed: 0,
            error: err instanceof Error ? err.message : "entity worker failed",
          };
        }
      })
    );

    // ── Step 5: Aggregate results ──
    const succeeded = completionResults.filter((r) => r.success);
    const failed = completionResults.filter((r) => !r.success);

    // ── Step 6: Persist run records — one per (resource, entityType) ──
    if (completionResults.length > 0) {
      await step.run("persist-run-records", async () => {
        const now = new Date().toISOString();
        for (const r of completionResults) {
          const sharedFields = {
            since,
            depth,
            status: r.success ? "completed" : "failed",
            pagesProcessed: r.pagesProcessed,
            eventsProduced: r.eventsProduced,
            eventsDispatched: r.eventsDispatched,
            error: r.success ? null : (r.error ?? null),
            completedAt: now,
            updatedAt: now,
          };

          await db
            .insert(gatewayBackfillRuns)
            .values({
              installationId,
              entityType: r.entityType,
              providerResourceId: r.resourceId,
              ...sharedFields,
              startedAt: now,
            })
            .onConflictDoUpdate({
              target: [
                gatewayBackfillRuns.installationId,
                gatewayBackfillRuns.providerResourceId,
                gatewayBackfillRuns.entityType,
              ],
              set: sharedFields,
            });
        }
      });
    }

    // ── Step 7: Replay held webhooks (replaces relay.replayCatchup) ──
    // When holdForReplay is set, entity workers persist webhooks without delivery.
    // After all workers complete, drain them by querying DB directly and sending
    // memory/webhook.received events so they are processed in chronological order.
    if (holdForReplay && succeeded.length > 0) {
      log.info("[backfill-orchestrator] replaying held webhooks", {
        installationId,
        succeededWorkers: succeeded.length,
        correlationId,
      });
      await step.run("replay-held-webhooks", async () => {
        const BATCH_SIZE = 200;
        const MAX_ITERATIONS = 500; // Safety cap: 500 * 200 = 100k webhooks max
        let iterations = 0;
        const processedIds: string[] = [];

        while (iterations < MAX_ITERATIONS) {
          iterations++;

          // Query un-delivered webhooks for this installation
          const conditions = [
            eq(gatewayWebhookDeliveries.installationId, installationId),
            eq(gatewayWebhookDeliveries.status, "held"),
          ];
          if (processedIds.length > 0) {
            conditions.push(
              notInArray(gatewayWebhookDeliveries.id, processedIds)
            );
          }

          const deliveries = await db
            .select()
            .from(gatewayWebhookDeliveries)
            .where(and(...conditions))
            .orderBy(gatewayWebhookDeliveries.receivedAt)
            .limit(BATCH_SIZE);

          if (deliveries.length === 0) {
            break;
          }

          // Send each delivery as a memory/webhook.received event
          const events = deliveries
            .filter((d) => d.payload)
            .map((d) => ({
              name: "memory/webhook.received" as const,
              data: {
                provider: d.provider,
                deliveryId: d.deliveryId,
                eventType: d.eventType,
                resourceId: null as string | null,
                payload: JSON.parse(d.payload!) as unknown,
                receivedAt: new Date(d.receivedAt).getTime(),
                preResolved: {
                  connectionId: installationId,
                  orgId: connection.orgId,
                },
                correlationId,
              },
            }));

          if (events.length > 0) {
            await inngest.send(events);
          }

          // Mark replayed deliveries so they aren't re-sent on retry (held -> enqueued)
          const replayedIds = deliveries.map((d) => d.id);
          if (replayedIds.length > 0) {
            await db
              .update(gatewayWebhookDeliveries)
              .set({ status: "enqueued" })
              .where(
                and(
                  eq(gatewayWebhookDeliveries.installationId, installationId),
                  inArray(gatewayWebhookDeliveries.id, replayedIds)
                )
              );
          }

          // Track processed IDs to exclude from next batch
          for (const d of deliveries) {
            processedIds.push(d.id);
          }
        }

        if (iterations >= MAX_ITERATIONS) {
          log.error("[backfill] replay-held-webhooks hit iteration cap", {
            installationId,
            iterations,
            correlationId,
          });
        }
      });
    }

    log.info("[backfill-orchestrator] complete", {
      installationId,
      provider,
      completed: succeeded.length,
      failed: failed.length,
      eventsProduced: completionResults.reduce(
        (sum, r) => sum + r.eventsProduced,
        0
      ),
      eventsDispatched: completionResults.reduce(
        (sum, r) => sum + r.eventsDispatched,
        0
      ),
      correlationId,
    });

    return {
      success: failed.length === 0,
      installationId,
      provider,
      workUnits: workUnits.length,
      skipped: workUnits.length - filteredWorkUnits.length,
      dispatched: filteredWorkUnits.length,
      completed: succeeded.length,
      failed: failed.length,
      eventsProduced: completionResults.reduce(
        (sum, r) => sum + r.eventsProduced,
        0
      ),
      eventsDispatched: completionResults.reduce(
        (sum, r) => sum + r.eventsDispatched,
        0
      ),
      results: completionResults,
    };
  }
);

/**
 * Entity embed workflow
 *
 * Subscribes to entity.graphed (NOT entity.upserted) so that graph edges are
 * committed before the narrative is built. This avoids the race condition where
 * concurrent entity-embed and entity-graph functions both start from the same
 * entity.upserted event and entity-embed reads stale edges.
 *
 * Debounced per entity: burst events collapse into a single embed call.
 */

import { buildOrgNamespace } from "@db/app";
import { db } from "@db/app/client";
import {
  orgEntities,
  orgEntityEdges,
  orgEventEntities,
  orgEvents,
} from "@db/app/schema";
import type { EntityVectorMetadata } from "@repo/app-validation";
import { EMBEDDING_DEFAULTS } from "@repo/app-validation";
import { NonRetriableError } from "@vendor/inngest";
import { log } from "@vendor/observability/log/next";
import { asc, desc, eq, sql } from "drizzle-orm";
import {
  buildEntityNarrative,
  narrativeHash,
} from "../../lib/narrative-builder";
import { inngest } from "../client";
import { createNeuralOnFailureHandler } from "../on-failure-handler";

/**
 * Hard character cap applied to the narrative before embedding.
 *
 * Cohere embed-english-v3.0 has a 512-token context window. English text
 * averages ~4 chars/token, so 512 tokens ~ 2,048 chars. We cap at 1,800
 * (~ 450 tokens) to leave a 62-token safety buffer and accommodate any
 * non-English content in entity keys or values.
 *
 * The narrative sections are ordered most-important-first (identity ->
 * genesis -> temporal span -> recent events -> graph edges), so if the cap
 * ever fires, it discards from the least-important tail.
 *
 * @see vendor/embed/src/provider/cohere.ts — truncate: "NONE" will surface
 * an error if this cap fails to hold (e.g. a very long entity.value in
 * Section 1).
 */
const NARRATIVE_CHAR_CAP = 1800;

export const memoryEntityEmbed = inngest.createFunction(
  {
    id: "memory/entity.embed",
    name: "Entity Embed",
    description:
      "Builds entity narrative and upserts to Pinecone (layer=entities)",
    debounce: {
      // Collapse burst events for the same entity into one embed call
      key: "event.data.entityExternalId",
      period: "30s",
    },
    retries: 3,
    timeouts: { finish: "2m" },
    onFailure: createNeuralOnFailureHandler("memory/entity.graphed"),
  },
  { event: "memory/entity.graphed" },
  async ({ event, step }) => {
    const { clerkOrgId, entityExternalId, provider, correlationId } =
      event.data;

    log.info("[entity-embed] starting", {
      clerkOrgId,
      entityExternalId,
      provider,
      correlationId,
    });

    // Step 1: Fetch all narrative inputs in a single step.
    // Throws NonRetriableError for missing rows so Inngest does not retry infinitely.
    const entity = await step.run("fetch-entity", async () => {
      const row = await db.query.orgEntities.findFirst({
        where: eq(orgEntities.externalId, entityExternalId),
        columns: {
          id: true,
          externalId: true,
          category: true,
          key: true,
          value: true,
          extractedAt: true,
          lastSeenAt: true,
          occurrenceCount: true,
        },
      });
      if (!row) {
        log.warn("[entity-embed] entity not found, aborting", {
          entityExternalId,
          correlationId,
        });
        throw new NonRetriableError(`Entity not found: ${entityExternalId}`);
      }
      return row;
    });

    const [genesisResults, recentEvents, edges, maxSignificanceResults] =
      await step.run("fetch-narrative-inputs", async () => {
        return Promise.all([
          // Genesis event (first ever — founding context, never lost)
          db
            .select({
              title: orgEvents.title,
              sourceType: orgEvents.sourceType,
              occurredAt: orgEvents.occurredAt,
            })
            .from(orgEventEntities)
            .innerJoin(orgEvents, eq(orgEventEntities.eventId, orgEvents.id))
            .where(eq(orgEventEntities.entityId, entity.id))
            .orderBy(asc(orgEvents.occurredAt))
            .limit(1),

          // Last 3 events (recency signal + current state)
          db
            .select({
              title: orgEvents.title,
              sourceType: orgEvents.sourceType,
              occurredAt: orgEvents.occurredAt,
            })
            .from(orgEventEntities)
            .innerJoin(orgEvents, eq(orgEventEntities.eventId, orgEvents.id))
            .where(eq(orgEventEntities.entityId, entity.id))
            .orderBy(desc(orgEvents.occurredAt))
            .limit(3),

          // Graph edges — both outgoing and incoming, mapped to "related entity".
          // LIMIT 3 per direction: each edge line is ~180 chars / ~45 tokens.
          // See NARRATIVE_CHAR_CAP for the full token budget reasoning.
          db
            .select({
              relationshipType: orgEntityEdges.relationshipType,
              targetCategory: orgEntities.category,
              targetKey: orgEntities.key,
            })
            .from(orgEntityEdges)
            .innerJoin(
              orgEntities,
              eq(orgEntityEdges.targetEntityId, orgEntities.id)
            )
            .where(eq(orgEntityEdges.sourceEntityId, entity.id))
            .limit(3)
            .union(
              db
                .select({
                  relationshipType: orgEntityEdges.relationshipType,
                  targetCategory: orgEntities.category,
                  targetKey: orgEntities.key,
                })
                .from(orgEntityEdges)
                .innerJoin(
                  orgEntities,
                  eq(orgEntityEdges.sourceEntityId, orgEntities.id)
                )
                .where(eq(orgEntityEdges.targetEntityId, entity.id))
                .limit(3)
            ),

          // Max significance score across all events for this entity
          db
            .select({
              max: sql<number>`MAX(${orgEvents.significanceScore})`,
            })
            .from(orgEventEntities)
            .innerJoin(orgEvents, eq(orgEventEntities.eventId, orgEvents.id))
            .where(eq(orgEventEntities.entityId, entity.id)),
        ]);
      });

    const genesisEvent = genesisResults[0] ?? null;
    const maxSignificanceScore = maxSignificanceResults[0]?.max ?? 0;

    // Build narrative text and hash outside of a step (CPU-only, no I/O)
    const narrative = buildEntityNarrative(
      entity,
      genesisEvent,
      recentEvents,
      edges
    );
    const hash = narrativeHash(narrative);
    const latestEvent = recentEvents[0];

    // Cap the narrative to NARRATIVE_CHAR_CAP characters before embedding.
    // Sections are ordered most-important-first; the cap discards from the tail.
    // truncate: "NONE" in the Cohere provider will surface an error if this cap
    // ever fails to hold (e.g. an unusually long entity.value in Section 1).
    const cappedNarrative = narrative.slice(0, NARRATIVE_CHAR_CAP);
    if (narrative.length > NARRATIVE_CHAR_CAP) {
      log.warn("[entity-embed] narrative capped", {
        entityExternalId,
        original: narrative.length,
        cap: NARRATIVE_CHAR_CAP,
        correlationId,
      });
    }

    // Step 2: Embed the narrative using constants
    const embedding = await step.run("embed-narrative", async () => {
      const { createEmbeddingProviderForOrg } = await import("@repo/app-embed");
      const embeddingProvider = createEmbeddingProviderForOrg(
        {
          id: clerkOrgId,
          embeddingModel: EMBEDDING_DEFAULTS.embeddingModel,
          embeddingDim: EMBEDDING_DEFAULTS.embeddingDim,
        },
        { inputType: "search_document" }
      );

      const { embeddings } = await embeddingProvider.embed([cappedNarrative]);
      const vector = embeddings[0];
      if (!vector) {
        log.error("[entity-embed] embedding provider returned no vector", {
          entityExternalId,
          correlationId,
        });
        throw new Error("Embedding provider returned no vector");
      }
      return vector;
    });

    // Step 3: UPSERT single entity vector to Pinecone
    await step.run("upsert-entity-vector", async () => {
      const { appPineconeClient } = await import("@repo/app-pinecone");
      const indexName = EMBEDDING_DEFAULTS.indexName;
      const namespaceName = buildOrgNamespace(clerkOrgId);

      const metadata: EntityVectorMetadata = {
        layer: "entities",
        entityExternalId: entity.externalId,
        entityType: entity.category,
        provider,
        latestAction: latestEvent?.sourceType.split(".").pop() ?? "",
        title: narrative.split("\n")[0] ?? entity.key,
        snippet: narrative.slice(0, 500),
        // Unix ms timestamps — numeric for reliable Pinecone range filters
        occurredAt: latestEvent
          ? new Date(latestEvent.occurredAt).getTime()
          : Date.now(),
        createdAt: new Date(entity.extractedAt).getTime(),
        narrativeHash: hash,
        totalEvents: entity.occurrenceCount,
        significanceScore: maxSignificanceScore,
      };

      await appPineconeClient.upsertVectors<EntityVectorMetadata>(
        indexName,
        {
          ids: [`ent_${entity.externalId}`],
          vectors: [embedding],
          metadata: [metadata],
        },
        namespaceName
      );

      log.info("[entity-embed] entity vector upserted", {
        entityExternalId: entity.externalId,
        entityType: entity.category,
        vectorId: `ent_${entity.externalId}`,
        totalEvents: entity.occurrenceCount,
        edgeCount: edges.length,
        narrativeHash: hash,
        correlationId,
      });
    });

    return {
      entityExternalId: entity.externalId,
      narrativeHash: hash,
      totalEvents: entity.occurrenceCount,
      edgeCount: edges.length,
    };
  }
);

/**
 * Entity graph workflow
 *
 * Subscribes to entity.upserted, resolves entity<->entity edges via the
 * co-occurrence algorithm, then emits entity.graphed so entity-embed can
 * build its narrative with up-to-date graph context.
 *
 * Extracted from event-interpret.ts — graph resolution has no LLM dependency
 * and should not be blocked by classification latency.
 */

import { log } from "@vendor/observability/log/next";
import { resolveEdges } from "../../lib/edge-resolver";
import { inngest } from "../client";
import { createNeuralOnFailureHandler } from "../on-failure-handler";

export const memoryEntityGraph = inngest.createFunction(
  {
    id: "memory/entity.graph",
    name: "Entity Graph",
    description: "Resolves entity edges after upsert (fast, pure SQL)",
    retries: 3,
    timeouts: { finish: "2m" },
    onFailure: createNeuralOnFailureHandler("memory/entity.upserted"),
  },
  { event: "memory/entity.upserted" },
  async ({ event, step }) => {
    const { clerkOrgId, internalEventId, provider, entityRefs, correlationId } =
      event.data;

    const edgeCount = await step.run("resolve-edges", () =>
      resolveEdges(clerkOrgId, internalEventId, provider, entityRefs)
    );

    log.info("[entity-graph] edges resolved", {
      clerkOrgId,
      internalEventId,
      provider,
      entityExternalId: event.data.entityExternalId,
      edgeCount,
      correlationId,
    });

    await step.sendEvent("emit-entity-graphed", {
      name: "memory/entity.graphed" as const,
      data: {
        clerkOrgId,
        entityExternalId: event.data.entityExternalId,
        entityType: event.data.entityType,
        provider,
        occurredAt: event.data.occurredAt,
        correlationId,
      },
    });

    return { edgeCount };
  }
);

