1	/**
2	 * Neural Workflow onFailure Handler Factory
3	 *
4	 * Neural workflows share a common failure handling pattern:
5	 * 1. Extract the original event from Inngest's FailureEventPayload (event.data.event)
6	 * 2. Log the error with workflow-specific context fields
7	 * 3. Locate the job by inngestRunId and mark it as failed
8	 *
9	 * This factory encapsulates that boilerplate so each workflow only
10	 * declares what makes it unique: log message, context fields, output shape.
11	 *
12	 * @example
13	 * ```ts
14	 * onFailure: createNeuralOnFailureHandler(
15	 *   "memory/event.capture",
16	 *   {
17	 *     logMessage: "Event capture failed",
18	 *     logContext: ({ clerkOrgId, sourceEvent }) => ({ clerkOrgId, sourceId: sourceEvent.sourceId }),
19	 *     buildOutput: ({ data: { sourceEvent }, error }) => ({
20	 *       inngestFunctionId: "event.capture",
21	 *       status: "failure",
22	 *       sourceId: sourceEvent.sourceId,
23	 *       error,
24	 *     }),
25	 *   }
26	 * ),
27	 * ```
28	 */
29	
30	import type { NeuralFailureOutput, WorkflowOutput } from "@repo/app-validation";
31	import { log } from "@vendor/observability/log/next";
32	import { completeJob, getJobByInngestRunId } from "../lib/jobs";
33	import type { Events } from "./client";
34	
35	/**
36	 * Creates a consistent onFailure handler for neural Inngest workflows.
37	 *
38	 * @param _eventName - Event name used only for TypeScript generic inference.
39	 *   The `_` prefix signals intentional non-use at runtime.
40	 */
41	export function createNeuralOnFailureHandler<TEventName extends keyof Events>(
42	  _eventName: TEventName,
43	  config?: {
44	    logMessage: string;
45	    /** Returns loggable fields derived from the original event's data */
46	    logContext: (data: Events[TEventName]["data"]) => Record<string, unknown>;
47	    /** Constructs the failure output stored in the job record */
48	    buildOutput: (params: {
49	      data: Events[TEventName]["data"];
50	      error: string;
51	    }) => NeuralFailureOutput;
52	  }
53	) {
54	  return async ({
55	    event,
56	    error,
57	  }: {
58	    // Inngest's FailureEventPayload wraps the original event under data.event.
59	    // The exact FailureEventPayload generic shape is an Inngest internal —
60	    // the cast below re-establishes type safety.
61	    event: { data: { event: unknown } };
62	    error: Error;
63	  }) => {
64	    const originalEvent = event.data.event as {
65	      id: string;
66	      data: Events[TEventName]["data"];
67	    };
68	    const data = originalEvent.data;
69	    const eventId = originalEvent.id;
70	
71	    log.error(config?.logMessage ?? `${String(_eventName)} failed`, {
72	      ...(config?.logContext(data) ?? {}),
73	      error: error.message,
74	    });
75	
76	    if (config && eventId) {
77	      const job = await getJobByInngestRunId(eventId);
78	      if (job) {
79	        await completeJob({
80	          jobId: job.id,
81	          status: "failed",
82	          // NeuralFailureOutput's .catchall(z.unknown()) index signature is
83	          // structurally incompatible with Drizzle's WorkflowOutput column type.
84	          // The cast is safe: each workflow's buildOutput validates via satisfies.
85	          output: config.buildOutput({
86	            data,
