15	import { TRPCError } from "@trpc/server";
16	import { eq } from "@vendor/db";
17	import { log } from "@vendor/observability/log/next";
18	import { z } from "zod";
19	import { providerConfigs } from "../../lib/provider-configs";
20	import {
21	  forceRefreshToken,
22	  getActiveTokenForInstallation,
23	} from "../../lib/token-helpers";
24	import { serviceProcedure } from "../../trpc";
25	
26	// ── Proxy Router ────────────────────────────────────────────────────────────
27	
