1	/**
2	 * Lazy-initialized provider configs — built on first access from validated env vars.
3	 *
4	 * Ported from apps/gateway/src/routes/connections.ts (lines 44–64).
5	 * Uses the memory app's base URL for OAuth callbacks instead of the gateway.
6	 *
7	 * IMPORTANT: Lazy initialization prevents build-time crashes when env vars
8	 * are not yet available during `next build` static analysis.
9	 */
10	import type { RuntimeConfig } from "@repo/app-providers";
11	import { PROVIDERS } from "@repo/app-providers";
12	import { appUrl } from "./related-projects";
13	
14	let _providerConfigs: Record<string, unknown> | null = null;
15	
16	/**
17	 * Configs keyed by provider name — built on first access.
18	 *
19	 * Optional providers return null from createConfig when their env vars are absent —
20	 * they are excluded and will return "unknown_provider" on any request.
21	 */
22	export function getProviderConfigs(): Record<string, unknown> {
23	  if (!_providerConfigs) {
24	    const runtime: RuntimeConfig = { callbackBaseUrl: appUrl };
25	    _providerConfigs = Object.fromEntries(
26	      Object.entries(PROVIDERS)
27	        .map(([name, p]) => [name, p.createConfig(p.env, runtime)] as const)
28	        .filter(([, config]) => config !== null)
29	    );
30	  }
31	  return _providerConfigs;
32	}
33	
34	/**
35	 * @deprecated Use getProviderConfigs() instead. This is a compatibility alias
36	 * that lazily initializes on first property access.
37	 */
38	export const providerConfigs: Record<string, unknown> = new Proxy(
39	  {} as Record<string, unknown>,
40	  {
41	    get(_target, prop) {
42	      return getProviderConfigs()[prop as string];
43	    },
44	    has(_target, prop) {
45	      return prop in getProviderConfigs();
