/**
 * Delivery recovery cron function
 *
 * Replaces QStash-scheduled POST /admin/recovery/cron in the relay service.
 * Source logic: apps/relay/src/lib/replay.ts + apps/relay/src/routes/admin.ts (lines 224-249)
 *
 * Sweeps all deliveries stuck in status='received' for more than 5 minutes
 * across all providers and installations, then sends memory/webhook.received
 * events for each one instead of re-triggering Upstash Workflows.
 */

import { db } from "@db/app/client";
import { gatewayInstallations, gatewayWebhookDeliveries } from "@db/app/schema";
import type { SourceType } from "@repo/app-providers";
import { getProvider, isWebhookProvider } from "@repo/app-providers";
import { and, eq, lt } from "@vendor/db";
import { log } from "@vendor/observability/log/next";
import { inngest } from "../client";

export const deliveryRecovery = inngest.createFunction(
  {
    id: "platform/delivery.recovery",
    name: "Delivery Recovery (5m cron)",
    retries: 1,
    concurrency: [{ limit: 1 }],
  },
  { cron: "*/5 * * * *" },
  async ({ step }) => {
    const BATCH_SIZE = 100;
    const STALE_THRESHOLD_MS = 5 * 60 * 1000; // 5 minutes

    // -- Step 1: Find stuck deliveries --------------------------------------
    const deliveries = await step.run("find-stuck-deliveries", async () => {
      const staleBeforeIso = new Date(
        Date.now() - STALE_THRESHOLD_MS
      ).toISOString();

      return db
        .select()
        .from(gatewayWebhookDeliveries)
        .where(
          and(
            eq(gatewayWebhookDeliveries.status, "received"),
            lt(gatewayWebhookDeliveries.receivedAt, staleBeforeIso)
          )
        )
        .orderBy(gatewayWebhookDeliveries.receivedAt)
        .limit(BATCH_SIZE);
    });

    if (deliveries.length === 0) {
      return { replayed: 0, skipped: 0, failed: 0 };
    }

    log.info("[delivery-recovery] found stuck deliveries", {
      count: deliveries.length,
    });

    // -- Step 2: Re-send each as memory/webhook.received --------------------
    const result = await step.run("replay-deliveries", async () => {
      const replayed: string[] = [];
      const skipped: string[] = [];
      const failed: string[] = [];

      for (const delivery of deliveries) {
        if (!delivery.payload) {
          skipped.push(delivery.deliveryId);
          continue;
        }

        try {
          const parsedPayload = JSON.parse(delivery.payload) as unknown;
          const providerName = delivery.provider as SourceType;

          // Re-extract resourceId from stored payload via provider
          let resourceId: string | null = null;
          try {
            const providerDef = getProvider(providerName);
            if (providerDef && isWebhookProvider(providerDef)) {
              resourceId =
                providerDef.webhook.extractResourceId(parsedPayload) ?? null;
            }
          } catch {
            // If extraction fails, proceed with null — ingest delivery handles it
          }

          // Resolve connection info for preResolved if installationId is available
          let preResolved: { connectionId: string; orgId: string } | undefined;
          if (delivery.installationId) {
            // Look up orgId from installation
            const installationRows = await db
              .select({ orgId: gatewayInstallations.orgId })
              .from(gatewayInstallations)
              .where(eq(gatewayInstallations.id, delivery.installationId))
              .limit(1);

            if (installationRows[0]?.orgId) {
              preResolved = {
                connectionId: delivery.installationId,
                orgId: installationRows[0].orgId,
              };
            }
          }

          // Send as Inngest event instead of Upstash Workflow trigger
          await inngest.send({
            name: "platform/webhook.received",
            data: {
              provider: providerName,
              deliveryId: delivery.deliveryId,
              eventType: delivery.eventType,
              resourceId,
              payload: parsedPayload,
              receivedAt: new Date(delivery.receivedAt).getTime(),
              ...(preResolved ? { preResolved } : {}),
            },
          });

          replayed.push(delivery.deliveryId);

          // Reset status — ingest delivery will advance to processed
          try {
            await db
              .update(gatewayWebhookDeliveries)
              .set({ status: "received" })
              .where(
                and(
                  eq(gatewayWebhookDeliveries.provider, delivery.provider),
                  eq(gatewayWebhookDeliveries.deliveryId, delivery.deliveryId)
                )
              );
          } catch (err) {
            log.error("[delivery-recovery] DB status update failed", {
              deliveryId: delivery.deliveryId,
              error: err,
            });
          }
        } catch {
          failed.push(delivery.deliveryId);
        }
      }

      return { replayed, skipped, failed };
    });

    log.info("[delivery-recovery] complete", {
      replayed: result.replayed.length,
      skipped: result.skipped.length,
      failed: result.failed.length,
    });

    return {
      replayed: result.replayed.length,
      skipped: result.skipped.length,
      failed: result.failed.length,
    };
  }
);

/**
 * Connection lifecycle (teardown) function
 *
 * Ported from apps/gateway/src/workflows/connection-teardown.ts
 *
 * KEY CHANGES vs gateway service:
 * - Upstash Workflow context.run() → Inngest step.run()
 * - Function ID: memory/connection.lifecycle
 * - Trigger: memory/connection.lifecycle event (was Upstash Workflow trigger)
 * - Cancel backfill: fires Inngest event instead of QStash publish
 * - All 5 steps preserved: close-gate, cancel-backfill, revoke-token, cleanup-cache, remove-resources
 */

import { db } from "@db/app/client";
import {
  gatewayInstallations,
  gatewayLifecycleLogs,
  gatewayTokens,
  orgIntegrations,
} from "@db/app/schema";
import type { SourceType } from "@repo/app-providers";
import { getProvider } from "@repo/app-providers";
import { decrypt } from "@repo/lib";
import { eq } from "@vendor/db";
import { log } from "@vendor/observability/log/next";
import { getEncryptionKey } from "../../lib/encryption";
import { providerConfigs } from "../../lib/provider-configs";
import { inngest } from "../client";

export const connectionLifecycle = inngest.createFunction(
  {
    id: "memory/connection.lifecycle",
    name: "Connection Lifecycle (Teardown)",
    retries: 3,
    concurrency: [
      // 1 teardown per connection at a time
      { limit: 1, key: "event.data.installationId" },
    ],
    timeouts: { start: "1m", finish: "5m" },
  },
  { event: "memory/connection.lifecycle" },
  async ({ event, step }) => {
    const { installationId, provider: providerName } = event.data;

    log.info("[connection-lifecycle] starting", {
      installationId,
      provider: providerName,
    });

    // Step 1: Close the ingress gate — all guards check status === 'active',
    // so setting 'revoked' immediately blocks new requests.
    await step.run("close-gate", async () => {
      await db
        .update(gatewayInstallations)
        .set({ status: "revoked", updatedAt: new Date().toISOString() })
        .where(eq(gatewayInstallations.id, installationId));

      await db.insert(gatewayLifecycleLogs).values({
        installationId,
        event: "gate_closed",
        fromStatus: "active",
        toStatus: "revoked",
        reason: "Ingress gate closed by teardown workflow",
        metadata: {
          step: "close-gate",
          workflowContext: "connection-lifecycle",
          triggeredBy: "system",
        },
      });

      log.info("[connection-lifecycle] gate closed", { installationId });
    });

    // Step 2: Cancel any running backfill (best-effort, via Inngest event)
    await step.run("cancel-backfill", async () => {
      try {
        await inngest.send({
          name: "memory/backfill.run.cancelled",
          data: {
            installationId,
          },
        });
        log.info("[connection-lifecycle] backfill cancellation sent", {
          installationId,
        });
      } catch (err) {
        log.warn(
          "[connection-lifecycle] backfill cancellation failed (best-effort)",
          {
            installationId,
            error: err instanceof Error ? err.message : String(err),
          }
        );
      }
    });

    // Step 3: Revoke token at provider (best-effort)
    await step.run("revoke-token", async () => {
      if (providerName === "github") {
        log.info(
          "[connection-lifecycle] skipping token revocation (github uses on-demand JWTs)",
          {
            installationId,
          }
        );
        return;
      }

      const providerDef = getProvider(providerName as SourceType);
      const config = providerConfigs[providerName];

      if (!config) {
        log.warn(
          "[connection-lifecycle] provider not configured, skipping token revocation",
          {
            installationId,
            provider: providerName,
          }
        );
        return;
      }

      const tokenRows = await db
        .select()
        .from(gatewayTokens)
        .where(eq(gatewayTokens.installationId, installationId))
        .limit(1);

      const tokenRow = tokenRows[0];
      if (!tokenRow) {
        log.info(
          "[connection-lifecycle] no token row found, skipping revocation",
          {
            installationId,
          }
        );
        return;
      }

      try {
        const auth = providerDef.auth;
        if (auth.kind === "oauth" && auth.revokeToken) {
          const decryptedToken = await decrypt(
            tokenRow.accessToken,
            getEncryptionKey()
          );
          await auth.revokeToken(config as never, decryptedToken);
        }
        log.info("[connection-lifecycle] token revoked", {
          installationId,
          provider: providerName,
        });
      } catch (err) {
        log.warn(
          "[connection-lifecycle] token revocation failed (best-effort)",
          {
            installationId,
            provider: providerName,
            error: err instanceof Error ? err.message : String(err),
          }
        );
      }
    });

    // Step 4: Disconnect org integrations and log resource disconnection.
    // For user-initiated disconnects the app-layer cascade may have already
    // set orgIntegrations.status → 'disconnected', but for health-check
    // triggers no cascade runs. We update unconditionally (idempotent).
    await step.run("disconnect-resources", async () => {
      const allResources = await db
        .select({ providerResourceId: orgIntegrations.providerResourceId })
        .from(orgIntegrations)
        .where(eq(orgIntegrations.installationId, installationId));

      if (allResources.length > 0) {
        const now = new Date().toISOString();
        await db
          .update(orgIntegrations)
          .set({
            status: "disconnected",
            statusReason: "installation_revoked",
            updatedAt: now,
          })
          .where(eq(orgIntegrations.installationId, installationId));
      }

      const resourceIdMap: Record<string, string> = {};
      for (const r of allResources) {
        resourceIdMap[r.providerResourceId] = "disconnected";
      }

      await db.insert(gatewayLifecycleLogs).values({
        installationId,
        event: "resources_removed",
        fromStatus: "revoked",
        toStatus: "revoked",
        reason: `Disconnected ${allResources.length} linked resource(s) during teardown`,
        resourceIds: resourceIdMap,
        metadata: { step: "disconnect-resources", triggeredBy: "system" },
      });

      log.info("[connection-lifecycle] resources disconnected", {
        installationId,
        count: allResources.length,
      });
    });

    log.info("[connection-lifecycle] teardown complete", {
      installationId,
      provider: providerName,
    });

    return { success: true, installationId };
  }
);

