/**
 * Connection lifecycle (teardown) function
 *
 * Ported from apps/gateway/src/workflows/connection-teardown.ts
 *
 * KEY CHANGES vs gateway service:
 * - Upstash Workflow context.run() → Inngest step.run()
 * - Function ID: memory/connection.lifecycle
 * - Trigger: memory/connection.lifecycle event (was Upstash Workflow trigger)
 * - Cancel backfill: fires Inngest event instead of QStash publish
 * - All 5 steps preserved: close-gate, cancel-backfill, revoke-token, cleanup-cache, remove-resources
 */

import { db } from "@db/app/client";
import {
  gatewayInstallations,
  gatewayLifecycleLogs,
  gatewayTokens,
  orgIntegrations,
} from "@db/app/schema";
import type { SourceType } from "@repo/app-providers";
import { getProvider } from "@repo/app-providers";
import { decrypt } from "@repo/lib";
import { eq } from "@vendor/db";
import { log } from "@vendor/observability/log/next";
import { getEncryptionKey } from "../../lib/encryption";
import { providerConfigs } from "../../lib/provider-configs";
import { inngest } from "../client";

export const connectionLifecycle = inngest.createFunction(
  {
    id: "platform/connection.lifecycle",
    name: "Connection Lifecycle (Teardown)",
    retries: 3,
    concurrency: [
      // 1 teardown per connection at a time
      { limit: 1, key: "event.data.installationId" },
    ],
    timeouts: { start: "1m", finish: "5m" },
  },
  { event: "platform/connection.lifecycle" },
  async ({ event, step }) => {
    const { installationId, provider: providerName } = event.data;

    log.info("[connection-lifecycle] starting", {
      installationId,
      provider: providerName,
    });

    // Step 1: Close the ingress gate — all guards check status === 'active',
    // so setting 'revoked' immediately blocks new requests.
    await step.run("close-gate", async () => {
      await db
        .update(gatewayInstallations)
        .set({ status: "revoked", updatedAt: new Date().toISOString() })
        .where(eq(gatewayInstallations.id, installationId));

      await db.insert(gatewayLifecycleLogs).values({
        installationId,
        event: "gate_closed",
        fromStatus: "active",
        toStatus: "revoked",
        reason: "Ingress gate closed by teardown workflow",
        metadata: {
          step: "close-gate",
          workflowContext: "connection-lifecycle",
          triggeredBy: "system",
        },
      });

      log.info("[connection-lifecycle] gate closed", { installationId });
    });

    // Step 2: Cancel any running backfill (best-effort, via Inngest event)
    await step.run("cancel-backfill", async () => {
      try {
        await inngest.send({
          name: "platform/backfill.run.cancelled",
          data: {
            installationId,
          },
        });
        log.info("[connection-lifecycle] backfill cancellation sent", {
          installationId,
        });
      } catch (err) {
        log.warn(
          "[connection-lifecycle] backfill cancellation failed (best-effort)",
          {
            installationId,
            error: err instanceof Error ? err.message : String(err),
          }
        );
      }
    });

    // Step 3: Revoke token at provider (best-effort)
    await step.run("revoke-token", async () => {
      if (providerName === "github") {
        log.info(
          "[connection-lifecycle] skipping token revocation (github uses on-demand JWTs)",
          {
            installationId,
          }
        );
        return;
      }

      const providerDef = getProvider(providerName as SourceType);
      const config = providerConfigs[providerName];

      if (!config) {
        log.warn(
          "[connection-lifecycle] provider not configured, skipping token revocation",
          {
            installationId,
            provider: providerName,
          }
        );
        return;
      }

      const tokenRows = await db
        .select()
        .from(gatewayTokens)
        .where(eq(gatewayTokens.installationId, installationId))
        .limit(1);

      const tokenRow = tokenRows[0];
      if (!tokenRow) {
        log.info(
          "[connection-lifecycle] no token row found, skipping revocation",
          {
            installationId,
          }
        );
        return;
      }

      try {
        const auth = providerDef.auth;
        if (auth.kind === "oauth" && auth.revokeToken) {
          const decryptedToken = await decrypt(
            tokenRow.accessToken,
            getEncryptionKey()
          );
          await auth.revokeToken(config as never, decryptedToken);
        }
        log.info("[connection-lifecycle] token revoked", {
          installationId,
          provider: providerName,
        });
      } catch (err) {
        log.warn(
          "[connection-lifecycle] token revocation failed (best-effort)",
          {
            installationId,
            provider: providerName,
            error: err instanceof Error ? err.message : String(err),
          }
        );
      }
    });

    // Step 4: Disconnect org integrations and log resource disconnection.
    // For user-initiated disconnects the app-layer cascade may have already
    // set orgIntegrations.status → 'disconnected', but for health-check
    // triggers no cascade runs. We update unconditionally (idempotent).
    await step.run("disconnect-resources", async () => {
      const allResources = await db
        .select({ providerResourceId: orgIntegrations.providerResourceId })
        .from(orgIntegrations)
        .where(eq(orgIntegrations.installationId, installationId));

      if (allResources.length > 0) {
        const now = new Date().toISOString();
        await db
          .update(orgIntegrations)
          .set({
            status: "disconnected",
            statusReason: "installation_revoked",
            updatedAt: now,
          })
          .where(eq(orgIntegrations.installationId, installationId));
      }

      const resourceIdMap: Record<string, string> = {};
      for (const r of allResources) {
        resourceIdMap[r.providerResourceId] = "disconnected";
      }

      await db.insert(gatewayLifecycleLogs).values({
        installationId,
        event: "resources_removed",
        fromStatus: "revoked",
        toStatus: "revoked",
        reason: `Disconnected ${allResources.length} linked resource(s) during teardown`,
        resourceIds: resourceIdMap,
        metadata: { step: "disconnect-resources", triggeredBy: "system" },
      });

      log.info("[connection-lifecycle] resources disconnected", {
        installationId,
        count: allResources.length,
      });
    });

    log.info("[connection-lifecycle] teardown complete", {
      installationId,
      provider: providerName,
    });

    return { success: true, installationId };
  }
);

/**
 * Ingest delivery workflow
 *
 * Replaces the relay Upstash Workflow (5 steps) + QStash dispatch +
 * console ingress Upstash Workflow (2 steps) with a single Inngest function.
 *
 * Steps:
 * 1. resolve-connection — query orgIntegrations, or use preResolved
 * 2. transform-and-store — call transformEnvelope, insert ingest log
 * 3. emit-event-capture — step.sendEvent("memory/event.capture")
 * 4. publish-realtime — Upstash Realtime SSE for console UI
 */

import { db } from "@db/app/client";
import {
  gatewayWebhookDeliveries,
  orgIngestLogs,
  orgIntegrations,
} from "@db/app/schema";
import type { ProviderSlug } from "@repo/app-providers";
import { sanitizePostTransformEvent } from "@repo/app-providers";
import type { EventNotification } from "@repo/app-upstash-realtime";
import { NonRetriableError } from "@vendor/inngest";
import { log } from "@vendor/observability/log/next";
import { and, eq } from "drizzle-orm";
import { transformEnvelope } from "../../lib/transform";
import { inngest } from "../client";

export const ingestDelivery = inngest.createFunction(
  {
    id: "memory/ingest.delivery",
    name: "Ingest Delivery",
    description:
      "Webhook delivery -> transform -> emit event.capture (replaces relay workflow + QStash + console ingress)",
    concurrency: {
      limit: 20,
      key: "event.data.provider",
    },
    retries: 3,
    timeouts: {
      start: "1m",
      finish: "3m",
    },
  },
  { event: "memory/webhook.received" },
  async ({ event, step }) => {
    const data = event.data;

    // Step 1: Resolve connection from resource ID or use preResolved
    const connectionInfo = await step.run("resolve-connection", async () => {
      if (data.preResolved) {
        return data.preResolved;
      }

      if (!data.resourceId) {
        return null;
      }

      const rows = await db
        .select({
          installationId: orgIntegrations.installationId,
          orgId: orgIntegrations.clerkOrgId,
        })
        .from(orgIntegrations)
        .where(
          and(
            eq(orgIntegrations.providerResourceId, data.resourceId),
            eq(orgIntegrations.status, "active")
          )
        )
        .limit(1);

      const row = rows[0];
      if (!row) {
        return null;
      }

      return { connectionId: row.installationId, orgId: row.orgId };
    });

    if (!connectionInfo?.orgId) {
      throw new NonRetriableError("no_connection");
    }

    // clerkOrgId IS the orgId
    const clerkOrgId = connectionInfo.orgId;

    log.info("[ingest-delivery] connection resolved", {
      clerkOrgId,
      provider: data.provider,
      deliveryId: data.deliveryId,
      correlationId: data.correlationId,
    });

    // Step 2: Transform envelope and store ingest log
    const result = await step.run("transform-and-store", async () => {
      const rawEvent = transformEnvelope({
        provider: data.provider as ProviderSlug,
        eventType: data.eventType,
        payload: data.payload,
        deliveryId: data.deliveryId,
        receivedAt: data.receivedAt,
        orgId: connectionInfo.orgId,
        connectionId: connectionInfo.connectionId,
      });

      if (!rawEvent) {
        log.info("[ingest-delivery] No transformer, skipping", {
          provider: data.provider,
          eventType: data.eventType,
          deliveryId: data.deliveryId,
          correlationId: data.correlationId,
        });
        return { status: "unsupported" as const };
      }

      const sourceEvent = sanitizePostTransformEvent(rawEvent);

      const [record] = await db
        .insert(orgIngestLogs)
        .values({
          clerkOrgId,
          deliveryId: data.deliveryId,
          sourceEvent,
          receivedAt: new Date(data.receivedAt).toISOString(),
          ingestionSource: "webhook",
        })
        .returning({ id: orgIngestLogs.id });

      if (!record) {
        throw new Error("Failed to insert ingest log");
      }

      log.info("[ingest-delivery] event stored", {
        ingestLogId: record.id,
        clerkOrgId,
        deliveryId: data.deliveryId,
        correlationId: data.correlationId,
      });

      return {
        status: "transformed" as const,
        sourceEvent,
        ingestLogId: record.id,
      };
    });

    // Unsupported event type — return early, no downstream events
    if (result.status === "unsupported") {
      await step.run("mark-delivery-skipped", async () => {
        await db
          .update(gatewayWebhookDeliveries)
          .set({ status: "skipped" })
          .where(eq(gatewayWebhookDeliveries.deliveryId, data.deliveryId));
      });
      return {
        status: "unsupported",
        provider: data.provider,
        eventType: data.eventType,
      };
    }

    // Step 3: Emit memory/event.capture to trigger the neural pipeline
    await step.sendEvent("emit-event-capture", {
      name: "memory/event.capture" as const,
      data: {
        clerkOrgId,
        sourceEvent: result.sourceEvent,
        ingestionSource: "webhook",
        ingestLogId: result.ingestLogId,
        correlationId: data.correlationId,
      },
    });

    // Step 4: Publish to Upstash Realtime for console SSE
    await step.run("publish-realtime", async () => {
      const { realtime } = await import("@repo/app-upstash-realtime");
      const channel = realtime.channel(`org-${clerkOrgId}`);
      await channel.emit("org.event", {
        eventId: result.ingestLogId,
        clerkOrgId,
        sourceEvent: result.sourceEvent,
      } satisfies EventNotification);

      log.info("[ingest-delivery] realtime notification published", {
        clerkOrgId,
        ingestLogId: result.ingestLogId,
        correlationId: data.correlationId,
      });
    });

    // Step 5: Mark delivery as processed
    await step.run("mark-delivery-processed", async () => {
      await db
        .update(gatewayWebhookDeliveries)
        .set({ status: "processed" })
        .where(eq(gatewayWebhookDeliveries.deliveryId, data.deliveryId));
    });

    return {
      status: "delivered",
      clerkOrgId,
      ingestLogId: result.ingestLogId,
    };
  }
);

